'use strict';
const test=require('node:test'),assert=require('node:assert/strict'),fs=require('node:fs'),path=require('node:path'),vm=require('node:vm');

function loadWorker(){const root=path.resolve(__dirname,'..'),messages=[],context={console,Uint8Array,Float32Array,ArrayBuffer,Math,JSON,Map,Set};context.globalThis=context;context.self=context;vm.createContext(context);context.importScripts=(...names)=>{for(const name of names)vm.runInContext(fs.readFileSync(path.join(root,'js',name),'utf8'),context,{filename:name});};context.postMessage=(message,transfers)=>messages.push({message,transfers});vm.runInContext(fs.readFileSync(path.join(root,'js/chunk-worker.js'),'utf8'),context,{filename:'chunk-worker.js'});return{context,messages};}

test('chunk worker emits deterministic transferable terrain and revision-tagged mesh buffers',()=>{const first=loadWorker(),request={data:{type:'terrain',cx:8,cz:8,seed:'worker-test',version:2}};first.context.onmessage(request);assert.equal(first.messages.length,1);const terrain=first.messages[0];assert.equal(terrain.message.type,'terrain');assert.equal(terrain.message.data.length,16*64*16);assert.equal(terrain.transfers.length,1);const copy=terrain.message.data.slice();first.context.onmessage({data:{type:'mesh',cx:8,cz:8,seed:'worker-test',version:2,revision:17,data:copy}});const mesh=first.messages[1];assert.equal(mesh.message.type,'mesh');assert.equal(mesh.message.revision,17);assert.equal(mesh.message.opaque.length%9,0);assert.equal(mesh.message.water.length%10,0);assert.equal(mesh.transfers.length,2);const second=loadWorker();second.context.onmessage(request);assert.deepEqual(Array.from(second.messages[0].message.data),Array.from(terrain.message.data));const different=loadWorker();different.context.onmessage({data:{...request.data,seed:'worker-test-different'}});assert.notDeepEqual(Array.from(different.messages[0].message.data),Array.from(terrain.message.data));});

test('streamed terrain includes deterministic biome ecology',()=>{const worker=loadWorker(),decorations=new Set([6,7,17,20,31,32]);let decorated=0;for(const [cx,cz] of [[5,4],[7,4]]){worker.context.onmessage({data:{type:'terrain',cx,cz,seed:'ecology-test',version:2}});const data=worker.messages.at(-1).message.data;for(const id of data)if(decorations.has(id)){decorated++;break;}}assert.equal(decorated,2);});
test('streamed terrain includes coordinate-stable biome props',()=>{const worker=loadWorker();worker.context.onmessage({data:{type:'terrain',cx:6,cz:3,seed:'ecology-test',version:2}});const ids=new Set(worker.messages[0].message.data);assert.ok(ids.has(18),'expected deterministic plains sprinkle props');});
test('streamed underground includes seeded geodes, wafer mines, and caramel drips',()=>{const worker=loadWorker();worker.context.onmessage({data:{type:'terrain',cx:1,cz:1,seed:'underground',version:2}});const geode=new Set(worker.messages.at(-1).message.data);assert.ok(geode.has(22)&&geode.has(18));worker.context.onmessage({data:{type:'terrain',cx:12,cz:12,seed:'underground',version:2}});const mine=new Set(worker.messages.at(-1).message.data);assert.ok(mine.has(21)&&mine.has(16));});
